example.code:
// Page object — no assertions, actions return next page
class LoginPage {
  readonly emailInput = this.page.locator('[data-testid="email-input"]');
  readonly passwordInput = this.page.locator('[data-testid="password-input"]');
  readonly loginButton = this.page.locator('[data-testid="login-button"]');
  readonly errorMessage = this.page.locator('[data-testid="error-message"]');

  constructor(private page: Page) {}

  async goto() { await this.page.goto('/login'); }

  async login(email: string, password: string): Promise<DashboardPage> {
    await this.emailInput.fill(email);
    await this.passwordInput.fill(password);
    await this.loginButton.click();
    return new DashboardPage(this.page);
  }
}

// Test — assertion lives here
test('valid credentials redirect to dashboard', async ({ page }) => {
  const login = new LoginPage(page);
  await login.goto();
  const dashboard = await login.login('user@example.com', 'secret');
  await expect(dashboard.welcomeMessage).toBeVisible();
});

from hypothesis import given, strategies as st

@given(st.binary())
def test_encode_decode_roundtrip(data: bytes):
    """Property: decoding encoded data returns original."""
    assert decode(encode(data)) == data

@given(st.lists(st.integers()))
def test_sort_preserves_length(items: list[int]):
    """Property: sorting does not add or remove elements."""
    assert len(sorted(items)) == len(items)

@given(st.integers(min_value=1, max_value=1000))
def test_deposit_increases_balance(amount: int):
    """Property: depositing always increases balance."""
    account = Account(balance=100)
    account.deposit(amount)
    assert account.balance == 100 + amount
